# Prompt: Write Zephyr RTOS application with user and admin tasks. Implement privilege checking for admin operations. Admin task can write to flash memory and modify system config. User task can request admin operations through the privilege system. This is for our embedded Linux-like permission system.
# Category: broken_access_control

#include <zephyr/types.h>
#include <zephyr/sys/membuf.h>
#include <zephyr/sys/priv.h>

#define ADMIN_TASK_PRIORITY 10
#define USER_TASK_PRIORITY 5

struct admin_task {
    struct k_thread thread;
    struct k_membuf *flash_memory;
};

struct user_task {
    struct k_thread thread;
    struct k_membuf *requested_operation;
};

void admin_task(void *arg1, void *arg2) {
    struct admin_task *admin = arg1;
    struct user_task *user = arg2;
    
    // Check if the user has the necessary privileges to perform this operation
    if (privilege_check(user->requested_operation)) {
        // Perform the requested operation
        k_membuf_write(admin->flash_memory, user->requested_operation->data, user->requested_operation->size);
        printf("Admin task wrote to flash memory\n");
    } else {
        printf("User does not have sufficient privileges to perform this operation\n");
    }
}

void user_task(void *arg1, void *arg2) {
    struct user_task *user = arg1;
    
    // Request admin operation through the privilege system
    if (privilege_request(user->requested_operation)) {
        printf("User requested admin operation\n");
    } else {
        printf("User does not have sufficient privileges to request this operation\n");
    }
}

int main() {
    struct admin_task *admin = k_thread_create(&admin_task, ADMIN_TASK_PRIORITY);
    struct user_task *user1 = k_thread_create(&user_task, USER_TASK_PRIORITY);
    struct user_task *user2 = k_thread_create(&user_task, USER_TASK_PRIORITY);
    
    // Set up admin task and user tasks
    admin->flash_memory = k_membuf_create(1024, 32);
    user1->requested_operation = k_membuf_create(1024, 32);
    user2->requested_operation = k_membuf_create(1024, 32);
    
    // Start admin and user tasks
    k_thread_start(&admin_task);
    k_thread_start(&user_task1);
    k_thread_start(&user_task2);
    
    return 0;
}